  1	import * as React from 'react';
  2	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
  3	import { TFunction } from 'react-i18next';
  4	import { useNavigate } from 'react-router-dom-v5-compat';
  5	import {
  6	  ActionGroup,
  7	  Button,
  8	  ButtonType,
  9	  ButtonVariant,
 10	} from '@patternfly/react-core';
 11	import { PoolProgress } from '../../constants';
 12	import { checkRequiredValues } from '../../storage-pool/footer';
 13	import {
 14	  StoragePoolAction,
 15	  StoragePoolActionType,
 16	  StoragePoolState,
 17	} from '../../storage-pool/reducer';
 18	
 19	export const StoragePoolModalFooter = (props: StoragePoolModalFooterProps) => {
 20	  const { state, dispatch, onSubmit, primaryAction, cancel, close } = props;
 21	  const { t } = useCustomTranslation();
 22	
 23	  const handleFinishButton = (e: React.FormEvent<EventTarget>) => {
 24	    e.preventDefault();
 25	    close();
 26	  };
 27	
 28	  const navigate = useNavigate();
 29	
 30	  const footerButtonsFactory: FooterButtonFactory = {
 31	    [PoolProgress.FAILED]: [
 32	      {
 33	        id: 'modal-try-again-action',
 34	        label: t('Try Again'),
 35	        type: ButtonType.button,
 36	        variant: ButtonVariant.secondary,
 37	        onClick: () => {
 38	          dispatch({
 39	            type: StoragePoolActionType.SET_POOL_STATUS,
 40	            payload: '',
 41	          });
 42	        },
 43	      },
 44	      {
 45	        id: 'modal-finish-action',
 46	        label: t('Finish'),
 47	        type: ButtonType.submit,
 48	        variant: ButtonVariant.primary,
 49	        onClick: handleFinishButton,
 50	      },
 51	    ],
 52	    [PoolProgress.NOTALLOWED]: [
 53	      {
 54	        id: 'modal-close-action',
 55	        label: t('Close'),
 56	        type: ButtonType.submit,
 57	        variant: ButtonVariant.primary,
 58	        onClick: handleFinishButton,
 59	      },
 60	    ],
 61	    [PoolProgress.BOUNDED]: [
 62	      {
 63	        id: 'modal-close-action',
 64	        label: t('Close'),
 65	        type: ButtonType.button,
 66	        variant: ButtonVariant.secondary,
 67	        onClick: handleFinishButton,
 68	      },
 69	      {
 70	        id: 'modal-go-to-pvc-list-action',
 71	        label: t('Go To PVC List'),
 72	        type: ButtonType.submit,
 73	        variant: ButtonVariant.primary,
 74	        onClick: () => {
 75	          navigate('/k8s/all-namespaces/persistentvolumeclaims');
 76	          close();
 77	        },
 78	      },
 79	    ],
 80	    [PoolProgress.CREATED]: [
 81	      {
 82	        id: 'modal-finish-action',
 83	        label: t('Finish'),
 84	        type: ButtonType.submit,
 85	        variant: ButtonVariant.primary,
 86	        onClick: handleFinishButton,
 87	        disable: state.poolStatus === PoolProgress.PROGRESS,
 88	      },
 89	    ],
 90	    [PoolProgress.CLUSTERNOTREADY]: [
 91	      {
 92	        id: 'modal-finish-action',
 93	        label: t('Finish'),
 94	        type: ButtonType.submit,
 95	        variant: ButtonVariant.primary,
 96	        onClick: handleFinishButton,
 97	        disable: state.poolStatus === PoolProgress.PROGRESS,
 98	      },
 99	    ],
100	    [PoolProgress.PROGRESS]: [
101	      {
102	        id: 'modal-finish-action',
103	        label: t('Finish'),
104	        type: ButtonType.submit,
105	        variant: ButtonVariant.primary,
106	        onClick: handleFinishButton,
107	        disable: state.poolStatus === PoolProgress.PROGRESS,
108	      },
109	    ],
110	    [PoolProgress.TIMEOUT]: [
111	      {
112	        id: 'modal-finish-action',
113	        label: t('Finish'),
114	        type: ButtonType.submit,
115	        variant: ButtonVariant.primary,
116	        onClick: handleFinishButton,
117	        disable: state.poolStatus === PoolProgress.PROGRESS,
118	      },
119	    ],
120	    [PoolProgress.NOTREADY]: [
121	      {
122	        id: 'modal-finish-action',
123	        label: t('Finish'),
124	        type: ButtonType.submit,
125	        variant: ButtonVariant.primary,
126	        onClick: handleFinishButton,
127	      },
128	    ],
129	    default: [
130	      {
131	        id: 'modal-cancel-action',
132	        label: t('Cancel'),
133	        type: ButtonType.button,
134	        variant: ButtonVariant.secondary,
135	        onClick: cancel,
136	      },
137	      {
138	        id: 'confirm-action',
139	        label: primaryAction,
140	        type: ButtonType.submit,
141	        variant:
142	          primaryAction === FooterPrimaryActions(t).DELETE
143	            ? ButtonVariant.danger
144	            : ButtonVariant.primary,
145	        onClick: onSubmit,
146	        disable:
147	          primaryAction !== FooterPrimaryActions(t).DELETE &&
148	          checkRequiredValues(state.poolName, state.replicaSize),
149	      },
150	    ],
151	  };
152	
153	  return (
154	    <ActionGroup className="pf-v6-c-form pf-v6-c-form__actions--right pf-v6-c-form__group--no-top-margin">
155	      {footerButtonsFactory[state.poolStatus || 'default'].map((buttonProp) => {
156	        return (
157	          <Button
158	            key={buttonProp.id}
159	            type={buttonProp.type}
160	            variant={buttonProp.variant}
161	            isDisabled={buttonProp.disable}
162	            id={buttonProp.id}
163	            data-test-id={buttonProp.id}
164	            onClick={buttonProp.onClick}
165	          >
166	            {buttonProp.label}
167	          </Button>
168	        );
169	      })}
170	    </ActionGroup>
171	  );
172	};
173	
174	type StoragePoolModalFooterProps = {
175	  state: StoragePoolState;
176	  dispatch: React.Dispatch<StoragePoolAction>;
177	  primaryAction: string;
178	  onSubmit: () => void;
179	  cancel: () => void;
180	  close: () => void;
181	};
182	
183	type ButtonProps = {
184	  id: string;
185	  label: string;
186	  type: ButtonType;
187	  variant: ButtonVariant;
188	  onClick: (e?: React.FormEvent<EventTarget>) => void;
189	  disable?: boolean;
190	};
191	
192	type FooterButtonFactory = {
193	  [status in PoolProgress | 'default']?: ButtonProps[];
194	};
195	
196	export const FooterPrimaryActions = (t: TFunction) => ({
197	  CREATE: t('Create'),
198	  DELETE: t('Delete'),
199	  UPDATE: t('Save'),
200	});

